mapper.select:
SELECT o.order_id, o.order_no, p.product_name, o.order_status, o.order_deadline, mr.employee_id, e.employee_name, o.difficulty_score, o.difficulty_grade FROM orders o JOIN product p ON o.product_id = p.product_id LEFT JOIN matching_record mr ON o.order_id = mr.order_id AND mr.matching_status IN ('CONFIRM', 'INPROGRESS', 'COMPLETE') LEFT JOIN employee e ON mr.employee_id = e.employee_id
AND o.order_status = #{status}
AND o.difficulty_grade = #{difficultyGrade}
AND (o.order_no LIKE CONCAT('%', #{keyword}, '%') OR p.product_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY o.order_deadline ASC
LIMIT #{size} OFFSET #{page}
